import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: "balance" | "final" | "none";
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
              variant="icon"
            />
            <CurrencyAmount
              notation="compact"
              value={value}
              currency={currency}
              naturalPrecision
            />
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

function getValueColor(
  colorMode: CashflowTableSummaryValueCellProps["colorMode"],
  value: number | null,
) {
  if (value === null) {
    return "text.primary";
  }

  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";

import { CashflowTableCell } from "../CashflowTableCell.tsx";
import type {
  CashflowPeriod,
  CategoryOption,
  CategoryType,
} from "../types/index.ts";
import { getCategoryLabel } from "../utils/index.ts";
import {
  CashflowCategoryRow,
  CashflowCategoryRowLabel,
} from "./CashflowCategory.tsx";
import { useCashflowTable } from "./CashflowTableContext.tsx";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryDataRowProps = {
  allCategories: Array<CategoryOption>;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryDataRow({
  allCategories,
  category,
  direction,
}: CashflowCategoryDataRowProps) {
  const { data } = useCashflowTable();
  const categoryLabel = getCategoryLabel(category, allCategories);

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel,
  });

  const getCategoryValue = (period: CashflowPeriod) =>
    (direction === "IN" ? period.incomeCategories : period.costsCategories).get(
      category,
    ) ?? 0;

  return (
    <CashflowCategoryRow>
      <CashflowCategoryRowLabel category={category} direction={direction}>
        {categoryLabel}
      </CashflowCategoryRowLabel>

      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={getCategoryValue(period)}
          columnIndex={index}
          dateFrom={period.dateFrom}
          colorMode="none"
          onClick={() => openDetail(index)}
        />
      ))}
    </CashflowCategoryRow>
  );
}

import { ReactNode, createContext, useContext, useMemo } from "react";

import type { Currency, Interval } from "../../types/cashflow.types.ts";
import type {
  CashFlowResponse,
  CashflowTableData,
  CategoryFilterState,
} from "../types/index.ts";
import { transformCashflowData } from "../utils/index.ts";

export type CashflowTableContextValue = {
  data: CashflowTableData | null;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
} & CategoryFilterState;

const CashflowTableContext = createContext<CashflowTableContextValue | null>(
  null,
);

export function useCashflowTable() {
  const context = useContext(CashflowTableContext);
  if (!context) {
    throw new Error(
      "useCashflowTable must be used within a CashflowTable provider",
    );
  }
  return context;
}

type CashflowTableProviderProps = {
  children: ReactNode;
  data: CashFlowResponse | undefined;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
  categoryFilterState: CategoryFilterState;
};

export function CashflowTableProvider({
  children,
  data,
  interval,
  currency,
  bankAccountIdArray,
  categoryFilterState,
}: CashflowTableProviderProps) {
  const tableData = useMemo(() => {
    if (!data) {
      return null;
    }
    return transformCashflowData(data);
  }, [data]);

  const context = useMemo(
    () => ({
      data: tableData,
      interval,
      currency,
      bankAccountIdArray,
      ...categoryFilterState,
    }),
    [tableData, interval, currency, bankAccountIdArray, categoryFilterState],
  );

  return (
    <CashflowTableContext.Provider value={context}>
      {children}
    </CashflowTableContext.Provider>
  );
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period, including quality information when available */
  finalBalance: {
    value: number;
    balanceQuality: BalanceQuality;
  } | null;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

