import { EmptyState } from "@dfp/react-components";
import { IconBarChart03 } from "@dfp/react-icons";

import { useTT } from "../useTT.ts";
import { CashflowTableSkeleton } from "./cashflow-table/CashflowTableSkeleton.tsx";
import {
  CategoryDetailPopoverProvider,
  useCashflowTable,
} from "./cashflow-table/components/index.ts";
import { CashflowTable } from "./cashflow-table/index.ts";

type CashflowTableSectionProps = {
  isLoading: boolean;
};

export function CashflowTableSection({ isLoading }: CashflowTableSectionProps) {
  const { tt } = useTT();
  const { data } = useCashflowTable();

  if (isLoading) {
    return <CashflowTableSkeleton />;
  }

  if ((data?.periods.length ?? 0) === 0) {
    return (
      <EmptyState
        icon={<IconBarChart03 />}
        title={tt("cashflowTable.noDataTitle")}
        subtitle={tt("cashflowTable.noDataMessage")}
      />
    );
  }
  return (
    <CategoryDetailPopoverProvider>
      <CashflowTable />
    </CategoryDetailPopoverProvider>
  );
}

